    47	func (tmpl *Template) embedAllBases(ctx context.Context, embedAll, defaultBase bool, seen map[string]bool) error {
    48		logrus.Debugf("Embedding templates into %q", tmpl.Locator)
    49		if defaultBase {
    50			configDir, err := dirnames.LimaConfigDir()
    51			if err != nil {
    52				return err
    53			}
    54			defaultBaseFilename := filepath.Join(configDir, filenames.Base)
    55			if _, err := os.Stat(defaultBaseFilename); err == nil {
    56				// turn string into single element list
    57				// empty concatenation works around bug https://github.com/mikefarah/yq/issues/2269
    58				tmpl.expr.WriteString("| ($a.base | select(type == \"!!str\")) |= [\"\" + .]\n")
    59				tmpl.expr.WriteString("| ($a.base | select(type == \"!!map\")) |= [[] + .]\n")
    60				// prepend base template at the beginning of the list
    61				fmt.Fprintf(&tmpl.expr, "| $a.base = [%q, $a.base[]]\n", defaultBaseFilename)
    62				if err := tmpl.evalExpr(); err != nil {
    63					return err
    64				}
    65			}
    66		}
    67		for {
    68			if err := tmpl.Unmarshal(); err != nil {
    69				return err
    70			}
    71			if len(tmpl.Config.Base) == 0 {
    72				break
    73			}
    74			baseLocator := tmpl.Config.Base[0]
    75			if baseLocator.Digest != nil {
    76				return fmt.Errorf("base %q in %q has specified a digest; digest support is not yet implemented", baseLocator.URL, tmpl.Locator)
    77			}
    78			isTemplate, _ := SeemsTemplateURL(baseLocator.URL)
    79			if isTemplate && !embedAll {
    80				// Once we skip a template: URL we can no longer embed any other base template
    81				for i := 1; i < len(tmpl.Config.Base); i++ {
    82					isTemplate, _ = SeemsTemplateURL(tmpl.Config.Base[i].URL)
    83					if !isTemplate {
    84						return fmt.Errorf("cannot embed template %q after not embedding %q", tmpl.Config.Base[i].URL, baseLocator.URL)
    85					}
    86				}
    87				break
    88				// TODO should we track embedding of template: URLs so we can warn if we embed a non-template: URL afterwards?
    89			}
    90	
    91			if seen[baseLocator.URL] {
    92				return fmt.Errorf("base template loop detected: template %q already included", baseLocator.URL)
    93			}
    94			seen[baseLocator.URL] = true
    95	
    96			// remove base[0] from template before merging
    97			if err := tmpl.embedBase(ctx, baseLocator, embedAll, seen); err != nil {
    98				return err
    99			}
   100		}
   101		if err := tmpl.embedAllScripts(ctx, embedAll); err != nil {
   102			return err
   103		}
   104		if len(tmpl.Bytes) > yBytesLimit {
   105			return fmt.Errorf("template %q embedding exceeded the size limit (%d bytes)", tmpl.Locator, yBytesLimit)
   106		}
   107		return nil
   108	}
