   134	// evalExprImpl evaluates tmpl.expr against one or more documents.
   135	// Called by evalExpr() and embedAllScripts() for single documents and merge() for 2 documents.
   136	func (tmpl *Template) evalExprImpl(prefix string, b []byte) error {
   137		var err error
   138		expr := prefix + tmpl.expr.String() + "| $a"
   139		tmpl.Bytes, err = yqutil.EvaluateExpression(expr, b)
   140		// Make sure the YAML ends with just a single newline
   141		tmpl.Bytes = append(bytes.TrimRight(tmpl.Bytes, "\n"), '\n')
   142		tmpl.Config = nil
   143		tmpl.expr.Reset()
   144		return tmpl.ClearOnError(err)
   145	}
   146	
   147	// evalExpr evaluates tmpl.expr against the tmpl.Bytes document.
   148	func (tmpl *Template) evalExpr() error {
   149		var err error
   150		if tmpl.expr.Len() > 0 {
   151			// There is just a single document; $a and $b are the same
   152			singleDocument := "select(document_index == 0) as $a | $a as $b\n"
   153			err = tmpl.evalExprImpl(singleDocument, tmpl.Bytes)
   154		}
   155		return err
   156	}
   157	
   158	// merge merges the base template into tmpl.
   159	func (tmpl *Template) merge(base *Template) error {
   160		if err := tmpl.mergeBase(base); err != nil {
   161			return tmpl.ClearOnError(err)
   162		}
   163		documents := fmt.Sprintf("%s\n---\n%s", string(tmpl.Bytes), string(base.Bytes))
   164		return tmpl.evalExprImpl(mergeDocuments, []byte(documents))
   165	}
   166	
   167	// mergeBase generates a yq script to merge the template with a base.
   168	// Most of the merging is done generically by the mergeDocuments script below.
   169	// Only thing left is to compare minimum version numbers and keep the highest version.
   170	func (tmpl *Template) mergeBase(base *Template) error {
   171		if err := tmpl.Unmarshal(); err != nil {
   172			return err
   173		}
   174		if err := base.Unmarshal(); err != nil {
   175			return err
   176		}
   177		if tmpl.Config.MinimumLimaVersion != nil && base.Config.MinimumLimaVersion != nil {
   178			if versionutil.GreaterThan(*base.Config.MinimumLimaVersion, *tmpl.Config.MinimumLimaVersion) {
   179				const minimumLimaVersion = "minimumLimaVersion"
   180				tmpl.copyField(minimumLimaVersion, minimumLimaVersion)
   181			}
   182		}
   183		var tmplOpts limatype.QEMUOpts
   184		if err := limayaml.Convert(tmpl.Config.VMOpts[limatype.QEMU], &tmplOpts, "vmOpts.qemu"); err != nil {
   185			return err
   186		}
   187		var baseOpts limatype.QEMUOpts
   188		if err := limayaml.Convert(base.Config.VMOpts[limatype.QEMU], &baseOpts, "vmOpts.qemu"); err != nil {
   189			return err
   190		}
   191		if tmplOpts.MinimumVersion != nil && baseOpts.MinimumVersion != nil {
   192			tmplVersion := *semver.New(*tmplOpts.MinimumVersion)
   193			baseVersion := *semver.New(*baseOpts.MinimumVersion)
   194			if tmplVersion.LessThan(baseVersion) {
   195				const minimumQEMUVersion = "vmOpts.qemu.minimumVersion"
   196				tmpl.copyField(minimumQEMUVersion, minimumQEMUVersion)
   197			}
   198		}
   199		return nil
   200	}
   201	
   202	// mergeDocuments copies over settings from the base that don't yet exist
   203	// in the template, and to append lists from the base to template lists.
   204	// Both head and line comments are copied over as well.
   205	//
   206	// It also handles these special cases:
   207	// * dns lists are not merged and only copied when the template doesn't have any dns entries at all.
   208	// * probes and provision scripts are appended in reverse order.
   209	// * mountTypesUnsupported have duplicate values removed.
   210	// * base is removed from the template.
   211	const mergeDocuments = `
   212	  select(document_index == 0) as $a
   213	| select(document_index == 1) as $b
   214	
   215	# $c will be mutilated to implement our own "merge only new fields" logic.
   216	| $b as $c
   217	
   218	# Delete the base that is being merged right now
   219	| $a | select(.base | tag == "!!seq") | del(.base[0])
   220	| $a | select(.base | (tag == "!!seq" and length == 0)) | del(.base)
   221	| $a | select(.base | t<response clipped><NOTE>Due to the max output limit, only part of this file has been shown to you. You should retry this tool after you have searched inside the file with `grep -n` in order to find the line numbers of what you are looking for.</NOTE>ag instead of !!seq.
   222	# Append the elements from the same path in $b.
   223	# Exception: base templates, provision scripts and probes are prepended instead.
   224	| $a | (.. | select(tag == "!!seq" and (path[0] | test("^(base|provision|probes)$") | not))) |=
   225	   (. + (path[] as $p ireduce ($b; .[$p])))
   226	| $a | (.. | select(tag == "!!seq" and (path[0] | test("^(base|provision|probes)$")))) |=
   227	   ((path[] as $p ireduce ($b; .[$p])) + .)
   228	
   229	# Copy head and line comments for existing lists that do not already have comments.
   230	# New lists and existing maps already have their comments updated by the $a * $c merge.
   231	| $a | (.. | select(tag == "!!seq" and (key | head_comment == "")) | key) head_comment |=
   232	   (((path[] as $p ireduce ($b; .[$p])) | key | head_comment) // "")
   233	| $a | (.. | select(tag == "!!seq" and (key | line_comment == "")) | key) line_comment |=
   234	   (((path[] as $p ireduce ($b; .[$p])) | key | line_comment) // "")
   235	
   236	# Make sure mountTypesUnsupported elements are unique.
   237	| $a | (select(.mountTypesUnsupported) | .mountTypesUnsupported) |= unique
   238	
   239	# Remove the custom tags again so they do not clutter up the YAML output.
   240	| $a | .. | select(tag == "!!tag") tag = ""
   241	`
   242	
   243	// listFields returns dst and src fields like "list[idx].field".
   244	func listFields(list string, dstIdx, srcIdx int, field string) (dst, src string) {
   245		dst = fmt.Sprintf("%s[%d]", list, dstIdx)
   246		src = fmt.Sprintf("%s[%d]", list, srcIdx)
   247		if field != "" {
   248			dst += "." + field
   249			src += "." + field
   250		}
   251		return dst, src
   252	}
   253	
   254	// copyField copies value and comments from $b.src to $a.dst.
   255	func (tmpl *Template) copyField(dst, src string) {
   256		fmt.Fprintf(&tmpl.expr, "| ($a.%s) = $b.%s\n", dst, src)
   257		// The head_comment is on the key and not the value, so needs to be copied explicitly.
   258		// Surprisingly the line_comment seems to be copied with the value already even though it is also on the key.
   259		fmt.Fprintf(&tmpl.expr, "| ($a.%s | key) head_comment = ($b.%s | key | head_comment)\n", dst, src)
   260	}
   261	
   262	// copyListEntryField copies $b.list[srcIdx].field to $a.list[dstIdx].field (including comments).
   263	// Note: field must not be "" and must not be a list field itself either.
   264	func (tmpl *Template) copyListEntryField(list string, dstIdx, srcIdx int, field string) {
   265		tmpl.copyField(listFields(list, dstIdx, srcIdx, field))
   266	}
   267	
   268	type commentType string
   269	
   270	const (
   271		headComment commentType = "head"
   272		lineComment commentType = "line"
   273	)
   274	
   275	// copyComment copies a non-empty head or line comment from $b.src to $a.dst, but only if $a.dst already exists.
   276	func (tmpl *Template) copyComment(dst, src string, commentType commentType, isMapElement bool) {
   277		onKey := ""
   278		if isMapElement {
   279			onKey = " | key" // For map elements the comments are on the keys and not the values.
   280		}
   281		// The expression is careful not to create a null $a.dst entry if $b.src has no comments and $a.dst didn't already exist.
   282		// e.g.: `| $a | (select(.foo) | .foo | key | select(head_comment == "" and ($b.bar | key | head_comment != ""))) head_comment |= ($b.bar | key | head_comment)`
   283		fmt.Fprintf(&tmpl.expr, "| $a | (select(.%s) | .%s%s | select(%s_comment == \"\" and ($b.%s%s | %s_comment != \"\"))) %s_comment |= ($b.%s%s | %s_comment)\n",
   284			dst, dst, onKey, commentType, src, onKey, commentType, commentType, src, onKey, commentType)
   285	}
   286	
   287	// copyComments copies all non-empty comments from $b.src to $a.dst.
   288	func (tmpl *Template) copyComments(dst, src string, isMapElement bool) {
   289		for _, commentType := range []commentType{headComment, lineComment} {
   290			tmpl.copyComment(dst, src, commentType, isMapElement)
   291		}
   292	}
   293	
   294	// copyListEntryComments copies all non-empty comments from $b.list[srcIdx].field to $a.list[dstIdx].field.
   295	func (tmpl *Template) copyListEntryComments(list string, dstIdx, srcIdx int, field string) {
   296		dst, src := listFields(list, dstIdx, srcIdx, field)
   297		isMapElement := field != ""
   298		tmpl.copyComments(dst, src, isMapElement)
   299	}
   300	
   301	func (tmpl *Template) deleteListEntry(list string, idx int) {
   302		fmt.Fprintf(&tmpl.expr, "| del($a.%s[%d], $b.%s[%d])\n", list, idx, list, idx)
   303	}
   304	
   305	// upgradeListEntryStringToMapField turns list[idx] from a string to a {field: list[idx]} map.
   306	func (tmpl *Template) upgradeListEntryStringToMapField(list string, idx int, field string) {
   307		// TODO the head_comment on the string becomes duplicated as a foot_comment on the new field; could be a yq bug?
   308		fmt.Fprintf(&tmpl.expr, "| ($a.%s[%d] | select(type == \"!!str\")) |= {\"%s\": .}\n", list, idx, field)
   309	}
   310	
   311	// combineListEntries combines entries based on a shared unique key.
   312	// If two entries share the same key, then any missing fields in the earlier entry are
   313	// filled in from the latter one. The latter one is then deleted.
   314	//
   315	// Notes:
   316	// * The field order is not maintained when entries with a matching key are merged.
   317	// * The unique keys (and mount locations) are assumed to not be subject to Go templating.
   318	// * A wildcard key '*' matches all prior list entries.
   319	func (tmpl *Template) combineListEntries() error {
   320		if err := tmpl.Unmarshal(); err != nil {
   321			return err
   322		}
   323	
   324		tmpl.combineAdditionalDisks()
   325		tmpl.combineMounts()
   326		tmpl.combineNetworks()
   327	
   328		return tmpl.evalExpr()
   329	}
