   332	// TODO: retrieve them using reflection from the Go type tags to avoid possible typos.
   333	
   334	// combineAdditionalDisks combines additionalDisks entries. The shared key is the disk name.
   335	func (tmpl *Template) combineAdditionalDisks() {
   336		const additionalDisks = "additionalDisks"
   337	
   338		diskIdx := make(map[string]int, len(tmpl.Config.AdditionalDisks))
   339		for src := 0; src < len(tmpl.Config.AdditionalDisks); {
   340			disk := tmpl.Config.AdditionalDisks[src]
   341			var from, to int
   342			if disk.Name == "*" {
   343				// copy to **all** previous entries
   344				from = 0
   345				to = src - 1
   346			} else {
   347				if i, ok := diskIdx[disk.Name]; ok {
   348					// copy to previous disk with the same diskIdx
   349					from = i
   350					to = i
   351				} else {
   352					// record disk index and continue with the next entry
   353					if disk.Name != "" {
   354						diskIdx[disk.Name] = src
   355					}
   356					src++
   357					continue
   358				}
   359			}
   360			for dst := from; dst <= to; dst++ {
   361				// upgrade additionalDisks[dst] from "disk" name string to {"name": "disk"} map so we can add fields
   362				upgradeDiskToMap := sync.OnceFunc(func() {
   363					tmpl.upgradeListEntryStringToMapField(additionalDisks, dst, "name")
   364				})
   365	
   366				dest := &tmpl.Config.AdditionalDisks[dst]
   367				if dest.Format == nil && disk.Format != nil {
   368					upgradeDiskToMap()
   369					tmpl.copyListEntryField(additionalDisks, dst, src, "format")
   370					dest.Format = disk.Format
   371				}
   372				// TODO: Does it make sense to merge "fsType" and "fsArgs" independently of each other?
   373				if dest.FSType == nil && disk.FSType != nil {
   374					upgradeDiskToMap()
   375					tmpl.copyListEntryField(additionalDisks, dst, src, "fsType")
   376					dest.FSType = disk.FSType
   377				}
   378				// "fsArgs" are inherited all-or-nothing; they are not appended
   379				if len(dest.FSArgs) == 0 && len(disk.FSArgs) != 0 {
   380					upgradeDiskToMap()
   381					tmpl.copyListEntryField(additionalDisks, dst, src, "fsArgs")
   382					dest.FSArgs = disk.FSArgs
   383				}
   384				// TODO: Is there a good reason not to copy comments from wildcard entries?
   385				if disk.Name != "*" {
   386					tmpl.copyListEntryComments(additionalDisks, dst, src, "")
   387				}
   388			}
   389			tmpl.Config.AdditionalDisks = slices.Delete(tmpl.Config.AdditionalDisks, src, src+1)
   390			tmpl.deleteListEntry(additionalDisks, src)
   391		}
   392	}
