		fmt.Fprintf(os.Stderr, "%s: DNS mismatch got=%v want=%v\nYAML:\n%s\n", name, gotDNS, wantDNS, tmpl.Bytes)
		os.Exit(1)
	}
	if wantHostResolver != nil {
		if tmpl.Config.HostResolver.Enabled == nil || *tmpl.Config.HostResolver.Enabled != *wantHostResolver {
			got := "<nil>"
			if tmpl.Config.HostResolver.Enabled != nil { got = fmt.Sprint(*tmpl.Config.HostResolver.Enabled) }
			fmt.Fprintf(os.Stderr, "%s: hostResolver mismatch got=%s want=%v\n", name, got, *wantHostResolver)
			os.Exit(1)
		}
	}
	fmt.Printf("%s ok dns=%v\n", name, gotDNS)
}

func boolp(v bool) *bool { return &v }

func main() {
	_ = net.IP{}
	dir, err := os.MkdirTemp("", "lima-dns-cases-")
	if err != nil { panic(err) }
	defer os.RemoveAll(dir)
	base := "images: [{location: /tmp/dummy.qcow2, arch: x86_64}]\ndns: [1.1.1.1, 8.8.8.8]\nhostResolver: {enabled: false}\n"
	run(dir, "base_dns_propagates", "base: [base/debian.yaml]\n", base, []string{"1.1.1.1", "8.8.8.8"}, boolp(false))
	run(dir, "main_dns_wins", "base: [base/debian.yaml]\ndns: [9.9.9.9]\n", base, []string{"9.9.9.9"}, boolp(false))
	run(dir, "empty_main_dns_stays_empty", "base: [base/debian.yaml]\ndns: []\n", base, nil, boolp(false))
}
